"""Pure pricing adapter over the Ratebook engine — no Home Assistant imports, fully testable.

The Home Assistant integration (``custom_components/ratebook``) is a thin shell over these
functions; keeping the logic here means the price math is unit-tested without the HA harness.
Functions take an explicit ``now``/``day`` so behavior is deterministic and timezone handling
stays in the HA layer. Prices are returned as floats (HA sensor states) computed from the
engine's exact Decimals.

``tier`` is the 0-based tier index to price at (0 = first/baseline tier). Households that
regularly exceed their baseline allowance should price at tier 1 — on tiered plans like
PG&E E-1/E-TOU-C the marginal price difference is ~20-25%.
"""

from __future__ import annotations

import json
from datetime import date, datetime, time, timedelta, tzinfo
from importlib import resources
from typing import Any

from ..ratebook import (
    BillingWindow,
    HolidayPolicy,
    Tariff,
    cheapest_charge_window,
    holiday_dates,
    hourly_marginal_prices,
)

# Resolve bundled tariffs relative to THIS package, so it works whether ratebook_ha is
# pip-installed or vendored into the Home Assistant integration under another package name.
_TARIFFS = resources.files(__package__).joinpath("tariffs")

#: Non-tariff files that live alongside the bundled tariff JSONs.
_NOT_TARIFFS = {"index.json"}


def list_bundled() -> list[str]:
    """Slugs of the bundled tariffs (without the .json extension)."""
    return sorted(
        p.name[:-5]
        for p in _TARIFFS.iterdir()
        if p.name.endswith(".json") and p.name not in _NOT_TARIFFS
    )


def bundled_index() -> list[dict[str, str]]:
    """Bundled tariffs as ``[{slug, label}, ...]`` sorted by label.

    Labels ("Utility — Plan (ST)") come from ``tariffs/index.json``, generated by
    ``scripts/sync_bundled_tariffs.py``; a slug missing from the index falls back to itself.
    """
    try:
        entries = json.loads(_TARIFFS.joinpath("index.json").read_text())
    except (FileNotFoundError, json.JSONDecodeError):
        entries = []
    labels = {e["slug"]: e["label"] for e in entries}
    return sorted(
        ({"slug": s, "label": labels.get(s, s)} for s in list_bundled()),
        key=lambda e: e["label"].lower(),
    )


def load_bundled(name: str) -> Tariff:
    return Tariff.from_json(json.loads(_TARIFFS.joinpath(f"{name}.json").read_text()))


def load_tariff(source: str | dict[str, Any]) -> Tariff:
    """Load a tariff from a JSON string or an already-parsed dict (the schema's to_json form)."""
    return Tariff.from_json(json.loads(source) if isinstance(source, str) else source)


def is_holiday(tariff: Tariff, day: date) -> bool:
    """Whether ``day`` prices on the weekend schedule because of the tariff's holiday rule."""
    sched = tariff.schedule
    if sched.holiday_policy is not HolidayPolicy.AS_WEEKEND or not sched.holidays:
        return False
    return day in holiday_dates(day.year, sched.holidays, sched.holiday_observance)


def hourly_schedule(tariff: Tariff, day: date, *, tier: int = 0) -> list[dict[str, Any]]:
    """24 ``{start, price}`` entries for ``day`` — the marginal $/kWh each hour.

    Naive local timestamps; kept for compatibility with the v0.1.0 attribute shape. New
    consumers should prefer :func:`nordpool_schedule`.
    """
    prices = hourly_marginal_prices(tariff, BillingWindow(day, 1), tier=tier)
    return [
        {"start": datetime.combine(day, time(h)).isoformat(), "price": float(prices[h])}
        for h in range(24)
    ]


def nordpool_schedule(
    tariff: Tariff, day: date, *, tier: int = 0, tz: tzinfo | None = None
) -> list[dict[str, Any]]:
    """24 ``{start, end, value}`` entries for ``day`` — the raw_today/raw_tomorrow shape the
    Nordpool/Energi Data Service ecosystem (charging integrations, blueprints, ApexCharts
    configs) consumes.

    Pass the Home Assistant timezone as ``tz`` so timestamps carry the correct UTC offset
    (Nordpool consumers compare against ``now()``, which is timezone-aware); tariff hours are
    wall-clock, so entries are built per local hour.
    """
    prices = hourly_marginal_prices(tariff, BillingWindow(day, 1), tier=tier)
    out: list[dict[str, Any]] = []
    for h in range(24):
        start = datetime.combine(day, time(h), tzinfo=tz)
        end = (
            datetime.combine(day + timedelta(days=1), time(0), tzinfo=tz)
            if h == 23
            else datetime.combine(day, time(h + 1), tzinfo=tz)
        )
        out.append({"start": start.isoformat(), "end": end.isoformat(), "value": float(prices[h])})
    return out


def current_price(tariff: Tariff, now: datetime, *, tier: int = 0) -> float:
    """Marginal $/kWh at ``now``."""
    prices = hourly_marginal_prices(tariff, BillingWindow(now.date(), 1), tier=tier)
    return float(prices[now.hour])


def cheapest_window(
    tariff: Tariff,
    start: date,
    *,
    days: int,
    charge_hours: int,
    after: datetime | None = None,
    tier: int = 0,
) -> dict[str, Any]:
    """Cheapest contiguous ``charge_hours`` block over ``days`` from ``start`` (EV charging).

    Pass ``after`` (e.g. ``now``) so the suggested window is always upcoming, never in the past.
    """
    cw = cheapest_charge_window(
        tariff, BillingWindow(start, days), charge_hours, not_before=after, tier=tier
    )
    return {
        "start": cw.start.isoformat(),
        "end": (cw.start + timedelta(hours=charge_hours)).isoformat(),
        "avg_rate": float(cw.avg_rate),
        "hours": charge_hours,
    }


def _hourly_rate(tariff: Tariff, ts: datetime, _cache: dict[date, Any], tier: int = 0) -> float:
    day = ts.date()
    if day not in _cache:
        _cache[day] = hourly_marginal_prices(tariff, BillingWindow(day, 1), tier=tier)
    return float(_cache[day][ts.hour])


def evcc_forecast(
    tariff: Tariff, start: datetime, hours: int, *, tier: int = 0
) -> list[dict[str, Any]]:
    """Hourly price forecast in evcc's custom-tariff shape: ``[{start, end, value}, ...]``.

    Timestamps are RFC3339 (``start.isoformat()`` — pass a timezone-aware ``start``); ``value``
    is the marginal $/kWh for that hour. Feed this to an evcc ``custom`` grid tariff via its
    ``http`` source (e.g. through the Home Assistant sensor's ``forecast`` attribute).
    """
    cache: dict[date, Any] = {}
    out: list[dict[str, Any]] = []
    for i in range(hours):
        ts = start + timedelta(hours=i)
        out.append(
            {
                "start": ts.isoformat(),
                "end": (ts + timedelta(hours=1)).isoformat(),
                "value": _hourly_rate(tariff, ts, cache, tier),
            }
        )
    return out


def emhass_cost_forecast(
    tariff: Tariff, start: datetime, hours: int, *, tier: int = 0
) -> list[float]:
    """Hourly marginal prices as an EMHASS ``load_cost_forecast`` list — current period first."""
    cache: dict[date, Any] = {}
    return [_hourly_rate(tariff, start + timedelta(hours=i), cache, tier) for i in range(hours)]
